import React from "react";

function Calendar({ activities, onAddActivity, onBack }) {
  const sortedActivities = [...activities].sort(
    (a, b) => new Date(a.dateTime) - new Date(b.dateTime)
  );

  const buttonStyle = {
    border: "none",
    padding: "0.7rem 1.1rem",
    borderRadius: 8,
    fontWeight: 600,
    cursor: "pointer",
    marginRight: "0.75rem"
  };

  return (
    <div>
      <h2 style={{ marginTop: 0 }}>Calendar Screen</h2>
      <p style={{ color: "#475569", marginTop: 0 }}>
        All saved activities with their weather-smart checklists.
      </p>

      {sortedActivities.length === 0 ? (
        <p>No activities saved yet.</p>
      ) : (
        sortedActivities.map((activity) => (
          <div
            key={activity.id}
            style={{
              border: "1px solid #e2e8f0",
              borderRadius: 12,
              padding: "1rem",
              marginBottom: "1rem",
              background: "#f8fafc"
            }}
          >
            <h3 style={{ marginTop: 0, marginBottom: "0.6rem" }}>{activity.name}</h3>
            <p style={{ margin: "0.2rem 0" }}>
              <strong>Date/Time:</strong> {new Date(activity.dateTime).toLocaleString()}
            </p>
            <p style={{ margin: "0.2rem 0" }}>
              <strong>Weather:</strong> {activity.weatherSummary}
            </p>

            {activity.screenshotPreviewUrl && (
              <img
                src={activity.screenshotPreviewUrl}
                alt="Activity screenshot"
                style={{
                  width: "100%",
                  maxWidth: 260,
                  borderRadius: 10,
                  border: "1px solid #cbd5e1",
                  marginTop: "0.5rem"
                }}
              />
            )}

            <p style={{ marginBottom: "0.4rem", marginTop: "0.9rem", fontWeight: 600 }}>Checklist:</p>
            <ul style={{ margin: 0, paddingLeft: "1.2rem" }}>
              {activity.checklist.map((item) => (
                <li key={item}>{item}</li>
              ))}
            </ul>
          </div>
        ))
      )}

      <button onClick={onAddActivity} style={{ ...buttonStyle, background: "#2563eb", color: "#fff" }}>
        Add Activity
      </button>
      <button onClick={onBack} style={{ ...buttonStyle, background: "#e2e8f0", color: "#0f172a" }}>
        Back to Dashboard
      </button>
    </div>
  );
}

export default Calendar;
